'use client'

import { useEffect, useRef, useState } from 'react'

export default function About() {
  const [isVisible, setIsVisible] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
        }
      },
      { threshold: 0.1 }
    )

    if (ref.current) {
      observer.observe(ref.current)
    }

    return () => observer.disconnect()
  }, [])

  const skills = [
    'Component Architecture',
    'Performance Optimization',
    'Design Systems',
    'Accessibility',
    'API Integration',
    'State Management',
  ]

  return (
    <section
      id="about"
      ref={ref}
      className="min-h-screen flex items-center justify-center py-20 px-6"
    >
      <div className="max-w-4xl w-full">
        <div className="grid md:grid-cols-2 gap-12 items-center">
          {/* Left: Image Placeholder */}
          <div
            className={`transition-all duration-700 ${
              isVisible
                ? 'opacity-100 translate-x-0'
                : 'opacity-0 -translate-x-10'
            }`}
          >
            <div className="relative">
              <div className="absolute inset-0 bg-gradient-to-br from-accent/20 to-secondary/20 rounded-2xl blur-3xl" />
              <div className="relative h-80 rounded-2xl border border-accent/30 bg-card overflow-hidden">
                <div className="w-full h-full bg-gradient-to-br from-accent/10 to-secondary/10 flex items-center justify-center">
                  <div className="text-center">
                    <div className="w-32 h-32 rounded-full bg-gradient-to-br from-accent to-secondary/50 mx-auto mb-4" />
                    <p className="text-muted-foreground">Profile</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Right: Content */}
          <div
            className={`transition-all duration-700 ${
              isVisible ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-10'
            }`}
          >
            <h2 className="text-4xl font-bold text-foreground mb-6">About Me</h2>
            <p className="text-muted-foreground text-lg leading-relaxed mb-6">
              I'm a passionate frontend engineer with{' '}
              <span className="text-accent font-semibold">
                4+ years of experience
              </span>
              {' '}building scalable web applications. I specialize in crafting
              beautiful, accessible, and performant user interfaces that solve
              real-world problems.
            </p>
            <p className="text-muted-foreground text-lg leading-relaxed mb-8">
              My expertise spans across modern frontend technologies, responsive
              design, and creating design systems that scale. I'm passionate
              about clean code, best practices, and mentoring junior developers.
            </p>

            {/* Skills Grid */}
            <div className="grid grid-cols-2 gap-3">
              {skills.map((skill, idx) => (
                <div
                  key={skill}
                  className="px-4 py-3 rounded-lg bg-card border border-accent/20 hover:border-accent/50 transition-all hover:bg-accent/5 cursor-default group"
                  style={{
                    transitionDelay: isVisible ? `${idx * 50}ms` : '0ms',
                    opacity: isVisible ? 1 : 0,
                    transform: isVisible ? 'translateY(0)' : 'translateY(10px)',
                  }}
                >
                  <p className="text-sm font-medium text-foreground group-hover:text-accent transition-colors">
                    {skill}
                  </p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}
